def is_closed(set_elements, operation, op_name):
    for a in set_elements:
        for b in set_elements:
            result = operation(a, b)
            if result not in set_elements:
                print(f'Not closed under {op_name}: {a} {op_name} {b} = {result} not in set')
                return False
    print(f'Set is closed under {op_name}')
    return True

# Example: Check closure of {0, 1, 2} under addition modulo 3
mod3_set = {0, 1, 2}
add_mod3 = lambda a, b: (a + b) % 3
is_closed(mod3_set, add_mod3, 'addition mod 3')
